import{_ as e,a as i,b as t,c as o}from"./chunks/查询额度成功.BYPQR2qF.js";import{_ as d,o as n,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Dodawanie kanału WebDAV","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/webdav.md","filePath":"pl-PL/upload/webdav.md","lastUpdated":1781962217000}'),p={name:"pl-PL/upload/webdav.md"};function s(c,a,z,w,k,y){return n(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="dodawanie-kanału-webdav" tabindex="-1">Dodawanie kanału WebDAV <a class="header-anchor" href="#dodawanie-kanału-webdav" aria-label="Permalink to &quot;Dodawanie kanału WebDAV&quot;">​</a></h1><h2 id="kiedy-warto-go-uzyc" tabindex="-1">Kiedy warto go użyć <a class="header-anchor" href="#kiedy-warto-go-uzyc" aria-label="Permalink to &quot;Kiedy warto go użyć&quot;">​</a></h2><p>Użyj kanału WebDAV, gdy:</p><ul><li>masz NAS, dysk chmurowy lub usługę pamięci z endpointem WebDAV.</li><li>chcesz zapisywać przesłane obrazy w swoim katalogu WebDAV.</li><li>chcesz, aby dane logowania były zapisane w tabeli D1 <code>upload_channels</code>, zamiast pozostawać długo widoczne w frontendzie.</li></ul><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Cel</th></tr></thead><tbody><tr><td>WebDAV Endpoint</td><td>Serwerowy URL WebDAV, np. <code>https://nas.example.com/dav</code>.</td></tr><tr><td>Nazwa użytkownika</td><td>Do logowania w usłudze WebDAV.</td></tr><tr><td>Hasło</td><td>Do logowania w usłudze WebDAV.</td></tr><tr><td>Tryb uwierzytelniania</td><td>Domyślnie <code>Basic</code>. Użyj <code>Digest</code> albo automatycznej negocjacji tylko wtedy, gdy wymaga tego serwer.</td></tr><tr><td>Katalog przechowywania</td><td>Katalog na pliki. Domyślnie <code>imgbed</code>.</td></tr></tbody></table><h2 id="gdzie-dodac-kanał" tabindex="-1">Gdzie dodać kanał <a class="header-anchor" href="#gdzie-dodac-kanał" aria-label="Permalink to &quot;Gdzie dodać kanał&quot;">​</a></h2><ol><li>Otwórz Ustawienia systemowe.</li><li>Przejdź do Ustawień przesyłania.</li><li>Kliknij Dodaj kanał w prawym górnym rogu.</li><li>Wybierz <code>WebDAV</code>.</li></ol><h2 id="opis-pol" tabindex="-1">Opis pól <a class="header-anchor" href="#opis-pol" aria-label="Permalink to &quot;Opis pól&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Działanie</th><th>Wymagane</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa kanału WebDAV, np. <code>koofr</code> lub <code>nas</code>.</td><td>Tak</td></tr><tr><td>Endpoint</td><td>Pełny endpoint WebDAV, z <code>https://</code>.</td><td>Tak</td></tr><tr><td>Nazwa użytkownika</td><td>Login WebDAV.</td><td>Tak</td></tr><tr><td>Hasło</td><td>Hasło WebDAV.</td><td>Tak</td></tr><tr><td>Tryb uwierzytelniania</td><td>Zwykle <code>Basic</code>; użyj <code>Digest</code>, jeśli serwer wymaga digest authentication.</td><td>Tak</td></tr><tr><td>Katalog przechowywania</td><td>Katalog, w którym zapisywane są pliki. Domyślnie <code>imgbed</code>.</td><td>Nie</td></tr></tbody></table><h2 id="przykład-fie-nl-tab-digital" tabindex="-1">Przykład: fie.nl.tab.digital <a class="header-anchor" href="#przykład-fie-nl-tab-digital" aria-label="Permalink to &quot;Przykład: fie.nl.tab.digital&quot;">​</a></h2><h3 id="_1-utworz-hasło-aplikacji" tabindex="-1">1. Utwórz hasło aplikacji <a class="header-anchor" href="#_1-utworz-hasło-aplikacji" aria-label="Permalink to &quot;1. Utwórz hasło aplikacji&quot;">​</a></h3><p>Otwórz ustawienia bezpieczeństwa konta, znajdź hasła aplikacji i utwórz nowe hasło aplikacji.</p><p><img src="'+e+'" alt="Utwórz hasło aplikacji" loading="lazy"></p><p>Po utworzeniu od razu skopiuj i zapisz nowe hasło aplikacji. Zwykle jest pokazywane tylko raz.</p><p><img src="'+i+'" alt="Zapisz nowe hasło aplikacji" loading="lazy"></p><h3 id="_2-wypełnij-konfiguracje-webdav-w-imgbed" tabindex="-1">2. Wypełnij konfigurację WebDAV w ImgBed <a class="header-anchor" href="#_2-wypełnij-konfiguracje-webdav-w-imgbed" aria-label="Permalink to &quot;2. Wypełnij konfigurację WebDAV w ImgBed&quot;">​</a></h3><p>Wróć do ImgBed i dodaj kanał WebDAV:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Wartość</th></tr></thead><tbody><tr><td>Endpoint</td><td>URL WebDAV podany przez <code>https://fie.nl.tab.digital/</code>.</td></tr><tr><td>Nazwa użytkownika</td><td>Twoja nazwa użytkownika WebDAV.</td></tr><tr><td>Hasło</td><td>Hasło aplikacji utworzone przed chwilą.</td></tr><tr><td>Tryb uwierzytelniania</td><td>W większości przypadków zacznij od <code>Basic</code>.</td></tr><tr><td>Katalog przechowywania</td><td>Domyślnie <code>imgbed</code>; możesz też użyć własnego katalogu.</td></tr></tbody></table><p><img src="'+t+'" alt="Wypełnianie konfiguracji" loading="lazy"></p><h2 id="zachowanie-przy-duzych-plikach" tabindex="-1">Zachowanie przy dużych plikach <a class="header-anchor" href="#zachowanie-przy-duzych-plikach" aria-label="Permalink to &quot;Zachowanie przy dużych plikach&quot;">​</a></h2><p>Kanał WebDAV używa teraz prawdziwego przesyłania częściowego opartego na sesji.</p><p>Małe pliki są przesyłane jako jeden pełny plik. Pliki większe niż 64 MiB są automatycznie dzielone na części po około 10 MiB i przesyłane do zdalnego katalogu chunków.</p><p>Usługa WebDAV nie musi obsługiwać <code>partial update</code> ani zapisu opartego na offsetach. ImgBed nie scala chunków na zdalnym serwerze w jeden duży plik. Zamiast tego zapisuje manifest chunków i podczas odczytu pliku czyta je po kolei.</p><p>W praktyce:</p><table tabindex="0"><thead><tr><th>Rozmiar pliku</th><th>Metoda uploadu</th><th>Układ w zdalnej pamięci</th></tr></thead><tbody><tr><td>64 MiB lub mniej</td><td>Normalny upload</td><td>Jeden pełny plik</td></tr><tr><td>Więcej niż 64 MiB</td><td>Sesyjny upload częściowy</td><td>Katalog chunków z wieloma częściami</td></tr></tbody></table><p>Katalog chunków wpływa tylko na układ w zdalnej pamięci. URL pliku w ImgBed się nie zmienia. Użytkownicy nadal otwierają plik przez oryginalny link <code>/file/...</code>.</p><h2 id="kroki-konfiguracji" tabindex="-1">Kroki konfiguracji <a class="header-anchor" href="#kroki-konfiguracji" aria-label="Permalink to &quot;Kroki konfiguracji&quot;">​</a></h2><ol><li>Otwórz Ustawienia przesyłania.</li><li>Kliknij Dodaj kanał.</li><li>Wybierz <code>WebDAV</code>.</li><li>Wpisz rozpoznawalną nazwę kanału, np. <code>koofr</code>.</li><li>Wpisz endpoint WebDAV, np. <code>https://app.koofr.net/dav/Koofr</code>.</li><li>Wpisz nazwę użytkownika i hasło.</li><li>Domyślnie zostaw tryb uwierzytelniania <code>Basic</code>.</li><li>Zostaw katalog przechowywania jako <code>imgbed</code> albo zmień na własny.</li><li>Kliknij Zapisz.</li><li>Po zapisaniu sprawdź kartę kanału, odpytaj pojemność, jeśli jest dostępna, i prześlij plik testowy.</li></ol><h2 id="jak-sprawdzic" tabindex="-1">Jak sprawdzić <a class="header-anchor" href="#jak-sprawdzic" aria-label="Permalink to &quot;Jak sprawdzić&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak sprawdzić</th></tr></thead><tbody><tr><td>Karta kanału jest widoczna</td><td>Po zapisaniu w Ustawieniach przesyłania powinna pojawić się karta WebDAV.</td></tr><tr><td>Kanał jest włączony</td><td>Przełącznik w prawym górnym rogu karty pozostaje włączony.</td></tr><tr><td>Dane są zapisane</td><td>Widok szczegółów pokazuje Endpoint, nazwę użytkownika, tryb uwierzytelniania i katalog.</td></tr><tr><td>Mały plik uploaduje się</td><td>Prześlij obraz testowy i sprawdź, czy plik pojawia się w katalogu WebDAV.</td></tr><tr><td>Reguła dużych plików działa</td><td>Pliki powyżej 64 MiB używają uploadu częściowego i tworzą zdalny katalog chunków.</td></tr><tr><td>Zapytanie o pojemność działa</td><td>Jeśli serwer wspiera informacje o pojemności, zapytanie pokaże użycie i całkowity rozmiar.</td></tr></tbody></table><p><img src="'+o+`" alt="Zapytanie o limit zakończone powodzeniem" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="dlaczego-duze-pliki-webdav-tworza-katalog-chunkow" tabindex="-1">Dlaczego duże pliki WebDAV tworzą katalog chunków? <a class="header-anchor" href="#dlaczego-duze-pliki-webdav-tworza-katalog-chunkow" aria-label="Permalink to &quot;Dlaczego duże pliki WebDAV tworzą katalog chunków?&quot;">​</a></h3><p>To obecna metoda przechowywania dużych plików.</p><p>Pliki większe niż 64 MiB nie są scalane w jeden duży plik zdalny. Są zapisywane jako katalog chunków. ImgBed zapisuje manifest i zwraca pełną zawartość, czytając części po kolei.</p><h3 id="co-najpierw-sprawdzic-jesli-upload-duzych-plikow-sie-nie-udaje" tabindex="-1">Co najpierw sprawdzić, jeśli upload dużych plików się nie udaje? <a class="header-anchor" href="#co-najpierw-sprawdzic-jesli-upload-duzych-plikow-sie-nie-udaje" aria-label="Permalink to &quot;Co najpierw sprawdzić, jeśli upload dużych plików się nie udaje?&quot;">​</a></h3><p>Najpierw sprawdź Endpoint, nazwę użytkownika, hasło i katalog przechowywania. Potem upewnij się, że usługa WebDAV pozwala tworzyć katalogi, zapisywać pliki i je czytać.</p><p>Jeśli zapytanie o pojemność się nie udaje, ale mały upload działa, serwer może po prostu nie wspierać raportowania pojemności albo je ograniczać. Nie musi to oznaczać, że upload nie działa.</p><h3 id="jaki-tryb-uwierzytelniania-wybrac" tabindex="-1">Jaki tryb uwierzytelniania wybrać? <a class="header-anchor" href="#jaki-tryb-uwierzytelniania-wybrac" aria-label="Permalink to &quot;Jaki tryb uwierzytelniania wybrać?&quot;">​</a></h3><p>Zacznij od <code>Basic</code>.</p><p>Jeśli serwer wyraźnie wymaga digest authentication, użyj <code>Digest</code>.</p><p>Jeśli nie masz pewności, użyj automatycznej negocjacji.</p><h2 id="szybka-lista" tabindex="-1">Szybka lista <a class="header-anchor" href="#szybka-lista" aria-label="Permalink to &quot;Szybka lista&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Przygotuj endpoint WebDAV, nazwę użytkownika i hasło</span></span>
<span class="line"><span>-&gt; Otwórz Ustawienia przesyłania</span></span>
<span class="line"><span>-&gt; Dodaj kanał</span></span>
<span class="line"><span>-&gt; Wybierz WebDAV</span></span>
<span class="line"><span>-&gt; Wpisz Endpoint / nazwę użytkownika / hasło</span></span>
<span class="line"><span>-&gt; Domyślnie zostaw tryb Basic</span></span>
<span class="line"><span>-&gt; Domyślnie zostaw katalog imgbed</span></span>
<span class="line"><span>-&gt; Zapisz</span></span>
<span class="line"><span>-&gt; Odpytaj pojemność</span></span>
<span class="line"><span>-&gt; Prześlij plik testowy</span></span></code></pre></div>`,45)])])}const g=d(p,[["render",s]]);export{b as __pageData,g as default};
